blocks.body:
{
    "level": "A1–B1",
    "intro": "W tej sekcji poznasz <strong>podstawową gramatykę</strong> języka angielskiego: kolejność słów w zdaniu, konstrukcje pytające i przeczące, przysłówki i okoliczności.",
    "rules": [
        {
            "label": "Word zamówienie",
            "color": "emerald",
            "text": "Podstawowa struktura <strong>S–V–O</strong> — podmiot, czasownik, dopełnienie:",
            "example": "Ona czyta książki codziennie."
        },
        {
            "label": "Pytania",
            "color": "blue",
            "text": "Czasownik pomocniczy <strong>do/does/did</strong> przed temat:",
            "example": "Lubisz pizzę?"
        },
        {
            "label": "Negacja",
            "color": "rose",
            "text": "Używamy <strong>do/robi/zrobiłem + nie</strong>:",
            "example": "Nie lubię jabłek."
        }
    ]
}

{
    "title": "1. Główne elementy zdania",
    "intro": "Zdanie angielskie zbudowane jest według przejrzystej struktury:",
    "items": [
        {
            "label": "Temat",
            "title": "Temat (S)",
            "subtitle": "Kto wykonuje czynność: ja, ty, ona, Tom"
        },
        {
            "label": "Czasownik",
            "title": " (V)",
            "subtitle": "Czynność lub stan: czytać, jeść, jest, mieć"
        },
        {
            "label": "Obiekt",
            "title": "Dodatek (O)",
            "subtitle": "Do do kogo/co skierowana jest akcja: książka, kawa"
        },
        {
            "label": "Przysłówki",
            "title": "Okoliczności",
            "subtitle": "Kiedy, gdzie, jak: wczoraj, w domu, szybko"
        }
    ]
}

{
    "title": "2. Typy zdań",
    "sections": [
        {
            "label": "Twierdzące",
            "color": "emerald",
            "description": "Podstawowa struktura S–V–O bez dodatkowych elementów.",
            "examples": [
                {
                    "en": "She reads books.",
                    "ua": "Вона читає книги."
                },
                {
                    "en": "They play football.",
                    "ua": "Вони грають у футбол."
                }
            ]
        },
        {
            "label": "Питальні",
            "color": "blue",
            "description": "Допоміжне дієслово <strong>do/does/did</strong> на початку.",
            "examples": [
                {
                    "en": "Lubisz pizzę?",
                    "ua": "Lubisz pizzę?"
                },
                {
                    "en": "Czy ona tu pracuje?",
                    "ua": "Ona tu pracuje?"
                }
            ]
        },
        {
            "label": "Negatywny",
            "color": "rose",
            "description": "Dodaj <strong>nie</strong> po czasownikach posiłkowych.",
            "examples": [
                {
                    "en": "Nie lubię kawy.",
                    "ua": "Nie lubię kawy."
                },
                {
                    "en": "Ona tu nie pracuje.",
                    "ua": "Ona tu nie pracuje."
                }
            ]
        }
    ]
}

{
    "title": "3. Kluczowe zasady",
    "items": [
        "Struktura podstawowa: <strong>S + V + O</strong> (podmiot + czasownik + dopełnienie).",
        "Przysłówki częstotliwości (<em>zawsze, często, nigdy</em>) - <strong>przed czasownikiem głównym</strong>.",
        "Okoliczności czasu i miejsca - zwykle <strong>na końcu</strong> zdania.",
        "Kolejność okoliczności: <strong>Sposób → Miejsce → Czas</strong>.",
        "W pytaniach czasownik pomocniczy <strong>przed podmiotem</strong>."
    ]
}
